const deleteWeek=(i)=>{
    showConfirmationModal(
        'Are you sure?',
        `You are going to delete this week. This process is irreversible`,
        'Delete'
    ).then(res=>{
        if(res){
            let weeks=Program.ExercisePlan.weeks
            weeks.splice(i,1)
           
            dispatch(updateProgram({
                ExercisePlan: {
                    ...Program.ExercisePlan,
                    weeks:weeks
                }
            }))
        }
    })

  
}

